const items = $input.all();

return items.map(item => {
  const nomeRaw    = $input.first().json.query.nome    || '';
  const cognomeRaw = $input.first().json.query.cognome || '';

  // Normalizza: UPPER + trim + single spaces
  const nomeNorm    = nomeRaw.trim().toUpperCase().replace(/\s+/g, ' ');
  const cognomeNorm = cognomeRaw.trim().toUpperCase().replace(/\s+/g, ' ');

  // Chiave unica combinata
  const chiaveNorm = `${nomeNorm} ${cognomeNorm}`.trim();

  // Normalizza email: lower + trim
  const emailRaw      = $input.first().json.query.email || '';
  const email_cliente = emailRaw.trim().toLowerCase();

  // Telefono
  const telefono = ($input.first().json.query.telefono || '').trim();

  // Dati appuntamento
  const datetime_iso        = $input.first().json.query.datetime_iso        || '';
  const data_appuntamento   = $input.first().json.query.data_appuntamento   || '';
  const ora_appuntamento    = $input.first().json.query.ora_appuntamento    || '';

  // Genera password casuale 10 caratteri
  const chars    = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789!@#';
  const password = Array.from({ length: 10 }, () =>
    chars[Math.floor(Math.random() * chars.length)]
  ).join('');

  return {
    json: {
      nome_norm:          nomeNorm,
      cognome_norm:       cognomeNorm,
      full_name:          `${nomeNorm} ${cognomeNorm}`.trim(),
      chiave_norm:        chiaveNorm,
      email_cliente:      email_cliente,
      telefono:           telefono,
      password:           password,
      datetime_iso:       datetime_iso,
      data_appuntamento:  data_appuntamento,
      ora_appuntamento:   ora_appuntamento,
    }
  };
});

