// Recupera folder_id da Crea Cartella Webhook (accessibile da Code node anche se in branch parallelo)
let folderId = '';
try {
  const folderData = $('Crea Cartella Webhook').item.json;
  folderId = folderData.id || folderData.folderId || '';
  console.log('[n8n] folder_id recuperato:', folderId || '(VUOTO)');
} catch(e) {
  console.warn('[n8n] Crea Cartella Webhook non accessibile:', e.message);
}
// Le foto arrivano nel body del webhook (POST)
const fotoArray = ($('Webhook Cal').item.json.body || {}).foto || [];
if (!Array.isArray(fotoArray) || fotoArray.length === 0) return [];

const userId = $input.item.json.id;
if (!userId) console.warn('[n8n] userId non trovato');

const results = [];
for (const foto of fotoArray) {
  const b64Raw = foto.data_base64 || '';
  const b64 = b64Raw.includes(',') ? b64Raw.split(',')[1] : b64Raw;
  if (!b64) continue;

  const fileName = foto.nome || 'foto.jpg';
  const mimeType = foto.tipo || 'image/jpeg';
  const buffer   = Buffer.from(b64, 'base64');
  const title    = fileName.replace(/\.[^.]+$/, '');
  const safeName = fileName.replace(/[^a-zA-Z0-9._-]/g, '_');
  const storagePath = userId ? (userId + '/' + Date.now() + '_' + safeName) : '';

  console.log('[n8n] Foto:', fileName, '| MIME:', mimeType, '| bytes:', buffer.length, '| userId:', userId ? 'ok' : 'MANCANTE');

  if (userId && storagePath) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: SUPABASE_URL + '/rest/v1/tattoo_gallery',
        headers: {
          'apikey':        SERVICE_ROLE,
          'Authorization': 'Bearer ' + SERVICE_ROLE,
          'Content-Type':  'application/json',
          'Prefer':        'return=minimal',
        },
        body: JSON.stringify({ client_id: userId, storage_path: storagePath, title }),
      });
      console.log('[n8n] DB insert ok. storagePath:', storagePath);
    } catch(e) {
      console.error('[n8n] DB insert fallito:', e.message);
    }
  }

  const binary = await this.helpers.prepareBinaryData(buffer, fileName, mimeType);
  results.push({
    json:   { nome: fileName, storagePath, mimeType, title, folder_id: folderId },
    binary: { data: binary },
  });
}

return results;

const items = $input.all();

return items.map(item => {
