const data = $input.item.json;

// Priorità 1: utente appena creato
const createdId = $('Crea Utente Auth').item.json.id;
const email = $('Estrai Dati Webhook').item.json.email;

if (createdId) {
  return [{ json: { id: createdId, email, isNewUser: true } }];
}

// Priorità 2: cerca nell'elenco utenti (GET /admin/users?per_page=1000)
const users = data.users || (Array.isArray(data) ? data : []);
const found = users.find(u => u.email === email);

if (!found?.id) {
  throw new Error('ID utente non trovato per: ' + email);
}

return [{ json: { id: found.id, email: found.email, isNewUser: false } }];

// Estrae i query params dal webhook e li passa come campi stabili.
// Tutti i nodi successivi referenziano QUESTO nodo (non il Webhook)
// così il nome del webhook non conta.
const q = $input.item.json.query;
return [{ json: {
  email:              q.email             || '',
  nome:               q.nome              || '',
  cognome:            q.cognome           || '',
  telefono:           q.telefono          || '',
  datetime_iso:       q.datetime_iso      || '',
  cal_booking_uid:    q.cal_booking_uid   || '',
  cal_booking_id:     q.cal_booking_id    || '',
  cal_booking_status: q.cal_booking_status || 'ACCEPTED',
  pagamento:          q.preferenza_pagamento || q.pagamento || null,
  luogo:              q.luogo             || q.location    || null,
  descrizione_idea:   q.descrizione_idea  || null
} }];

// Genera una password temporanea robusta (8 caratteri misti)
// e la aggiunge ai dati del webhook.
const d = $input.item.json;

const upper  = 'ABCDEFGHJKMNPQRSTUVWXYZ';
const lower  = 'abcdefghjkmnpqrstuvwxyz';
const digits = '23456789';

let pwd = '';
for (let i = 0; i < 3; i++) pwd += upper[Math.floor(Math.random() * upper.length)];
for (let i = 0; i < 3; i++) pwd += lower[Math.floor(Math.random() * lower.length)];
for (let i = 0; i < 2; i++) pwd += digits[Math.floor(Math.random() * digits.length)];

// Mescola i caratteri
pwd = pwd.split('').sort(() => Math.random() - 0.5).join('');

return [{ json: { ...d, temp_password: pwd } }];
